import sys

MOD = 998244353

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # Precompute the positions of each character in S
    char_pos = {}
    for i, c in enumerate(S):
        if c not in char_pos:
            char_pos[c] = []
        char_pos[c].append(i)

    # Initialize dp table: dp[m][l] = number of strings of length m with LCS length l
    dp = [[0] * (N + 1) for _ in range(M + 1)]
    dp[0][0] = 1

    # Fill the DP table
    for m in range(1, M + 1):
        for l in range(N + 1):
            # Case 1: current character is not in S
            dp[m][l] = (dp[m][l] + (26 - len(char_pos)) * dp[m - 1][l]) % MOD
            # Case 2: current character is in S, and we can extend a subsequence
            for c in char_pos:
                for pos in char_pos[c]:
                    if l > 0:
                        dp[m][l] = (dp[m][l] + dp[m - 1][l - 1]) % MOD
                    else:
                        dp[m][l] = (dp[m][l] + dp[m - 1][l]) % MOD

    # Compute the answer for each k from 0 to N
    ans = [0] * (N + 1)
    for k in range(N + 1):
        # Count number of strings with LCS length exactly k
        cnt_k = dp[M][k]
        for i in range(k + 1, N + 1):
            cnt_k = (cnt_k - dp[M][i]) % MOD
        ans[k] = cnt_k

    print(' '.join(map(str, ans)))

if __name__ == "__main__":
    main()
